pub struct Application {
    listener: TcpListener,
    pool: PgPool,
}

impl Application {
    pub async fn build(settings: &Settings) -> Result<Self, anyhow::Error> {
        let pool = PgPoolOptions::new()
            .max_connections(5)
            .connect_with(settings.database.connect_options())
            .await?;

        sqlx::migrate!("./migrations").run(&pool).await?;

        let session_store = PostgresStore::new(pool.clone());
        session_store.migrate().await?;

        let address = format!(
            "{}:{}",
            settings.application.host, settings.application.port
        );
        let listener = TcpListener::bind(&address).await?;

        tracing::info!("Listening on {}", listener.local_addr()?);

        Ok(Self { listener, pool })
    }

    pub fn port(&self) -> u16 {
        self.listener.local_addr().unwrap().port()
    }

    pub fn router(pool: PgPool) -> Router {
        let x_request_id = axum::http::HeaderName::from_static("x-request-id");

        let session_store = PostgresStore::new(pool.clone());
        let session_layer = SessionManagerLayer::new(session_store);

        Router::new()
            .route("/", axum::routing::get(index))
            .route("/dashboard", axum::routing::get(get_dashboard))
            .route("/inbox", axum::routing::get(get_inbox).post(post_inbox))
            .route(
                "/inbox/{id}/delete",
                axum::routing::post(post_delete_inbox_item),
            )
            .route(
                "/inbox/{id}/clarify",
                axum::routing::post(post_clarify_inbox_item),
            )
            .route(
                "/contexts",
                axum::routing::get(get_contexts).post(post_context),
            )
            .route(
                "/contexts/{id}/edit",
                axum::routing::get(get_edit_context).post(post_edit_context),
            )
            .route(
                "/contexts/{id}/delete",
                axum::routing::post(post_delete_context),
            )
            .route(
                "/next-actions",
                axum::routing::get(get_next_actions).post(post_next_action),
            )
            .route(
                "/next-actions/{id}",
                axum::routing::get(get_next_action_item),
            )
            .route(
                "/next-actions/{id}/complete",
                axum::routing::post(post_complete_next_action),
            )
            .route(
                "/next-actions/{id}/delete",
                axum::routing::post(post_delete_next_action),
            )
            .route(
                "/next-actions/{id}/edit",
                axum::routing::get(get_edit_next_action).post(post_edit_next_action),
            )
            .route("/projects", axum::routing::get(get_projects))
            .route("/waiting-for", axum::routing::get(get_waiting_for))
            .route("/someday-maybe", axum::routing::get(get_someday_maybe))
            .route("/review", axum::routing::get(get_review))
            .route(
                "/register",
                axum::routing::get(get_register).post(post_register),
            )
            .route("/login", axum::routing::get(get_login).post(post_login))
            .route("/forgot-password", axum::routing::get(get_forgot_password))
            .route("/logout", axum::routing::post(post_logout))
            .route("/todos", axum::routing::get(get_todos_page).post(post_todo))
            .route("/todos/{id}", axum::routing::get(get_todo_item))
            .route("/todos/{id}/toggle", axum::routing::post(post_toggle_todo))
            .route("/todos/{id}/delete", axum::routing::post(post_delete_todo))
            .route(
                "/todos/{id}/edit",
                axum::routing::get(get_edit_todo).post(post_edit_todo),
            )
            .route("/health_check", axum::routing::get(health_check))
            .nest_service("/static", ServeDir::new("static"))
            .layer(session_layer)
            .layer(TraceLayer::new_for_http())
            .layer(PropagateRequestIdLayer::new(x_request_id.clone()))
            .layer(SetRequestIdLayer::new(x_request_id, MakeRequestUuid))
            .with_state(pool)
    }

    pub async fn run(self) -> Result<(), std::io::Error> {
        let router = Self::router(self.pool);
        axum::serve(self.listener, router).await
    }
}

use sqlx::PgPool;

use crate::domain::{
    ContextId, InboxItem, InboxItemId, NextAction, TodoTitle, TodoTitleError, UserId,
};
use crate::infrastructure::inbox_repository;
use crate::infrastructure::next_action_repository;

#[derive(Debug, thiserror::Error)]
pub enum CaptureInboxError {
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "capture_inbox_item",
    skip(pool, title),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn capture_inbox_item(
    pool: &PgPool,
    user_id: UserId,
    title: String,
) -> Result<InboxItem, CaptureInboxError> {
    let title = TodoTitle::parse(title)?;
    let item = InboxItem::new(user_id, title);

    inbox_repository::insert_inbox_item(pool, &item)
        .await
        .map_err(|e| {
            CaptureInboxError::Unexpected(anyhow::anyhow!("Failed to insert inbox item: {e}"))
        })?;

    tracing::info!("Inbox item captured");
    Ok(item)
}

#[tracing::instrument(
    name = "get_inbox_items",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn get_inbox_items(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<InboxItem>, anyhow::Error> {
    let items = inbox_repository::find_inbox_items_by_user(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to fetch inbox items: {e}"))?;

    Ok(items)
}

#[tracing::instrument(
    name = "get_inbox_count",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn get_inbox_count(pool: &PgPool, user_id: &UserId) -> Result<i64, anyhow::Error> {
    let count = inbox_repository::count_inbox_items(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to count inbox items: {e}"))?;

    Ok(count)
}

#[derive(Debug, thiserror::Error)]
pub enum DeleteInboxError {
    #[error("Inbox item not found")]
    NotFound,
    #[error("Not authorized to delete this inbox item")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "delete_inbox_item",
    skip(pool),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn delete_inbox_item(
    pool: &PgPool,
    item_id: &InboxItemId,
    user_id: &UserId,
) -> Result<(), DeleteInboxError> {
    let item = inbox_repository::find_inbox_item_by_id(pool, item_id)
        .await
        .map_err(|e| DeleteInboxError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(DeleteInboxError::NotFound)?;

    if item.user_id() != user_id {
        return Err(DeleteInboxError::Unauthorized);
    }

    inbox_repository::delete_inbox_item(pool, item_id)
        .await
        .map_err(|e| {
            DeleteInboxError::Unexpected(anyhow::anyhow!("Failed to delete inbox item: {e}"))
        })?;

    tracing::info!("Inbox item deleted");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum ClarifyAsNextActionError {
    #[error("Inbox item not found")]
    NotFound,
    #[error("Not authorized to clarify this inbox item")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "clarify_as_next_action",
    skip(pool),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid(), context_id = %context_id.as_uuid())
)]
pub async fn clarify_as_next_action(
    pool: &PgPool,
    item_id: &InboxItemId,
    user_id: &UserId,
    context_id: ContextId,
) -> Result<NextAction, ClarifyAsNextActionError> {
    let item = inbox_repository::find_inbox_item_by_id(pool, item_id)
        .await
        .map_err(|e| ClarifyAsNextActionError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(ClarifyAsNextActionError::NotFound)?;

    if item.user_id() != user_id {
        return Err(ClarifyAsNextActionError::Unauthorized);
    }

    let action = NextAction::new(user_id.clone(), context_id, item.title().clone());

    next_action_repository::insert_next_action(pool, &action)
        .await
        .map_err(|e| {
            ClarifyAsNextActionError::Unexpected(anyhow::anyhow!(
                "Failed to insert next action: {e}"
            ))
        })?;

    inbox_repository::delete_inbox_item(pool, item_id)
        .await
        .map_err(|e| {
            ClarifyAsNextActionError::Unexpected(anyhow::anyhow!(
                "Failed to delete inbox item: {e}"
            ))
        })?;

    tracing::info!("Inbox item clarified as next action");
    Ok(action)
}

